here is my Optionsslist.tsx import React, { useState } from 'react';
import { ButtonItem } from 'decky-frontend-lib';
import { ipcRenderer } from 'electron';
import * as electron from 'electron';

export const OptionsList = () => {
  const [options, setOptions] = useState({
    epicGames: false,
  });

  const [progress, setProgress] = useState({
    epicGames: 0,
  });

  const handleButtonClick = (name: string) => {
    setOptions((prevOptions) => ({
      ...prevOptions,
      [name]: !prevOptions[name],
    }));
  };

  const handleInstallClick = () => {
    // Access the current state of the options variable here
    console.log(options);

    // Set the selected options
    const selectedOptions = Object.keys(options).filter((key) => options[key]);

    // Send a message to the backend with the selected options
    window.electron.ipcRenderer.send('install', selectedOptions);
  };

  return (
    <form>
      {/* Render a progress bar outside of the button here */}
      <progress value={progress.epicGames} max={100} />

      <ButtonItem
        className={options.epicGames ? 'selected' : ''}
        layout="below"
        onClick={() => handleButtonClick('epicGames')}
      >
        <span className="checkmark">{options.epicGames ? '✓' : ''}</span>{' '}
        Epic Games
      </ButtonItem>
      <br />

      {/* Add an Install button here using a ButtonItem component */}
      <ButtonItem layout="below" onClick={handleInstallClick}>
        Install
      </ButtonItem>

      <style>
        {`
          .checkmark {
            color: green;
          }
          .selected {
            background-color: #eee;
          }
          progress {
            display: block;
            width: 100%;
            margin-top: 5px;
            height: 20px; /* Change the height of the progress bar here */
          }
        `}
      </style>
    </form>
  );
};

